import{_ as a,o as e,c as r,ae as n}from"./chunks/framework.B6gjLfeO.js";const b=JSON.parse('{"title":"Clinch","description":"","frontmatter":{"title":"Clinch","slug":"clinch"},"headers":[],"relativePath":"marketer-hub/clinch.md","filePath":"marketer-hub/clinch.md"}'),o={name:"marketer-hub/clinch.md"};function i(l,t,d,s,c,h){return e(),r("div",null,[...t[0]||(t[0]=[n('<p><em>[Image: 1328]</em>.png &quot;Clinch + branch.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Clinch is an AI-powered Creative Personalization platform that delivers consumer-tailored ad experiences across all channels, to drive online and in-store performance and sales.</p><h3 id="partner-capabilities" tabindex="-1">Partner Capabilities <a class="header-anchor" href="#partner-capabilities" aria-label="Permalink to &quot;Partner Capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>DCO</td></tr><tr><td>Deep Linking</td><td>Not Supported</td></tr><tr><td>Attribution</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Ad Campaign Types</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Ad Formats</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Click Types</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Supported Platforms</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Link Wrapping</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Cost Ingestion Support</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Cost Ingestion Types</td><td>Contact support at Clinch for more information.</td></tr><tr><td>Pricing Models</td><td>Contact support at Clinch for more information.</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Clinch, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Performance <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Running campaigns through Clinch.</p></li></ol><h2 id="enable-clinch" tabindex="-1">Enable Clinch <a class="header-anchor" href="#enable-clinch" aria-label="Permalink to &quot;Enable Clinch&quot;">​</a></h2><h3 id="_1-enable-clinch-in-branch" tabindex="-1">1. Enable Clinch in Branch <a class="header-anchor" href="#_1-enable-clinch-in-branch" aria-label="Permalink to &quot;1. Enable Clinch in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads</strong> &gt; <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, find/search for Clinch. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_clinch?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>You&#39;ll need to input your <strong>Clinch Client ID (CID)</strong> and your <strong>Clinch Data Source ID (DSID)</strong>. Please reach out to your Clinch Account Manager for details.</p><p>Click the <strong>Save &amp; Enable</strong> button.</p><h3 id="_2-configure-postbacks" tabindex="-1">2. Configure Postbacks <a class="header-anchor" href="#_2-configure-postbacks" aria-label="Permalink to &quot;2. Configure Postbacks&quot;">​</a></h3><p>Enabling Clinch will automatically enable the following postbacks:</p><ul><li>INSTALL</li><li>PURCHASE</li><li>ADD_TO_CART</li><li>ADD_TO_WISHLIST</li><li>VIEW_CART</li><li>VIEW_ITEM</li><li>VIEW_ITEMS</li><li>INITIATE_PURCHASE</li></ul><p>You can configure these postbacks or add more under the <a href="https://dashboard.branch.io/ads/partner-management/a_clinch?tab=postback" target="_blank" rel="noreferrer"><strong>Postback Config</strong></a> tab.</p><h4 id="send-all-events" tabindex="-1">Send All Events <a class="header-anchor" href="#send-all-events" aria-label="Permalink to &quot;Send All Events&quot;">​</a></h4><p>Optionally, you can check the checkbox for a given postback for sending all events. When checked, all events will be sent regardless of attribution. Otherwise, the postback will only fire for events attributed to Clinch.</p><h4 id="adding-postbacks" tabindex="-1">Adding Postbacks <a class="header-anchor" href="#adding-postbacks" aria-label="Permalink to &quot;Adding Postbacks&quot;">​</a></h4><p>Click the <strong>Add New Postback</strong> button at the bottom of the screen. A modal will appear that will allow you to select an event that you are tracking with the Branch SDKs (including Custom Events).</p><p>.gif &quot;Add New Postbacks.gif&quot;)</p><p>For more in-depth postback configurations, view our guides:</p><ul><li><a href="./basic-postback-configuration.html">Basic Postback Configuration</a></li><li><a href="./advanced-postback-configuration.html">Advanced Postback Configuration</a></li><li><strong>Recommended</strong> 👍 <a href="./testing-postbacks.html">Test Postbacks</a></li></ul><h3 id="_3-configure-attribution-windows" tabindex="-1">3. Configure Attribution Windows <a class="header-anchor" href="#_3-configure-attribution-windows" aria-label="Permalink to &quot;3. Configure Attribution Windows&quot;">​</a></h3><p>After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_clinch?tab=attribution_windows" target="_blank" rel="noreferrer"><strong>Attribution Windows</strong></a> tab to set windows by attribution type.</p><h4 id="recommended-attribution-windows" tabindex="-1">Recommended Attribution Windows <a class="header-anchor" href="#recommended-attribution-windows" aria-label="Permalink to &quot;Recommended Attribution Windows&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Attribution Type</th><th>Window</th></tr></thead><tbody><tr><td>click to session start</td><td>90 days</td></tr><tr><td>click to install</td><td>30 days</td></tr><tr><td>click to conversion event</td><td>90 days</td></tr><tr><td>impression to session start</td><td>1 day</td></tr><tr><td>impression to install</td><td>1 day</td></tr><tr><td>impression to conversion event.</td><td>1 day</td></tr></tbody></table><h3 id="_4-create-branch-ad-link" tabindex="-1">4. Create Branch Ad Link <a class="header-anchor" href="#_4-create-branch-ad-link" aria-label="Permalink to &quot;4. Create Branch Ad Link&quot;">​</a></h3><p>Next, you&#39;ll need to create a Branch Ad Link for your Clinch campaigns in order for Branch to properly attribute conversions.</p><p>[.png)</p><p>help.branch.io</p><p>Create Ad Links](/docs/ad-links)</p><p>The Branch Ad Link you create will be placed in your Clinch campaign.</p><h3 id="_5-verify-data-in-branch" tabindex="-1">5. Verify Data in Branch <a class="header-anchor" href="#_5-verify-data-in-branch" aria-label="Permalink to &quot;5. Verify Data in Branch&quot;">​</a></h3><p>After launching your Clinch campaigns, and conversions begin to happen, you&#39;ll want to to verify data is being sent from Branch to Clinch. You can look at the <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Branch Dashboard&#39;s Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad partner (3p)</td><td>equals</td><td><code>a_clinch</code></td></tr></tbody></table><p>Once applied, data should flow through the Liveview, and you can see the data being sent to Clinch from Branch.</p>',38)])])}const u=a(o,[["render",i]]);export{b as __pageData,u as default};
